# Example: simplified gRPC client call (pseudo-Go) showing streaming fetch from Gitaly
package main

import (
  "context"
  "io"
  "log"
  pb "gitlab.com/gitaly/proto"
  "google.golang.org/grpc"
)

func fetchPack(addr, repoPath string) error {
  conn, err := grpc.Dial(addr, grpc.WithInsecure())
  if err != nil { return err }
  defer conn.Close()
  client := pb.NewRepositoryServiceClient(conn)

  stream, err := client.RemoteServiceFetch(context.Background(), &pb.FetchRequest{RepositoryPath: repoPath})
  if err != nil { return err }

  for {
    chunk, err := stream.Recv()
    if err == io.EOF { break }
    if err != nil { return err }
    // process chunk.PackData (write to local .git/objects/pack or stream to user)
  }
  return nil
}

