// Orchestrator example using async/await and persistent state (Node.js conceptual)
class SagaOrchestrator {
  constructor(store) { this.store = store; }

  async start(sagaId, steps, compensations, ctx) {
    await this.store.create(sagaId, { status: 'IN_PROGRESS', step: 0 });
    for (let i = 0; i < steps.length; i++) {
      try {
        await steps[i](ctx);
        await this.store.update(sagaId, { step: i+1 });
      } catch (err) {
        await this._compensate(sagaId, i-1, compensations, ctx);
        await this.store.update(sagaId, { status: 'FAILED', reason: err.message });
        throw err;
      }
    }
    await this.store.update(sagaId, { status: 'COMPLETED' });
  }

  async _compensate(sagaId, lastIndex, compensations, ctx) {
    for (let j = lastIndex; j >= 0; j--) {
      try { await compensations[j](ctx); }
      catch (e) { /* log, schedule retry, mark for manual intervention */ }
    }
  }
}
